// URL schemes safe to emit as the `href` of a rendered hyperlink in a
// read-only document viewer. Anything outside this list (most importantly
// `javascript:`, `data:`, `vbscript:`, `blob:`, `file:`) is rejected — the
// link is rendered as inert plain text instead. Fragment-only (`#foo`) and
// scheme-relative / path-relative URLs are treated as safe because they can't
// carry script. See SECURITY_REVIEW.md #2.
const SAFE_HREF_SCHEMES = new Set(['http:', 'https:', 'mailto:', 'tel:', 'ftp:', 'ftps:']);

// Five lowercase hex chars (20 bits, ~1M possible values). Generated by the
// platform CSPRNG so two simultaneous `renderAsync` calls that happen to
// share a `className` emit disjoint CSS counter names — see issue #181.
// The value only ever appears in class names and CSS counter identifiers
// that the renderer produces itself; it is never interpolated with DOCX
// data. Falls back to Math.random() only if a CSPRNG is unavailable (very
// old Node / embedded shells) — the uniqueness guarantee in that case is
// weakened but the API surface still works.
function generateRenderSessionId(): string {
	try {
		const bytes = new Uint8Array(3);
		if (typeof globalThis.crypto?.getRandomValues === 'function') {
			globalThis.crypto.getRandomValues(bytes);
			return Array.from(bytes, b => b.toString(16).padStart(2, '0')).join('').slice(0, 5);
		}
	} catch { /* fall through */ }
	return Math.floor(Math.random() * 0xfffff).toString(16).padStart(5, '0');
}

/**
 * Returns `true` iff `raw` can be safely emitted as the `href` of an `<a>` in
 * a read-only docx viewer. The allowlist accepts absolute URLs with known
 * safe schemes, fragment-only URLs (`#anchor`), and relative paths. All
 * other schemes — notably `javascript:` — are rejected.
 */
export function isSafeHyperlinkHref(raw: string | null | undefined): boolean {
	if (raw == null) return true; // empty href is inert
	if (typeof raw !== 'string') return false;
	const trimmed = raw.trim();
	if (trimmed === '') return true;
	if (trimmed.startsWith('#')) return true;
	try {
		// Resolve against a synthetic base so relative URLs parse but never
		// inherit the host document's base URI (which could be file:// in
		// embedding apps and pass the scheme allowlist accidentally).
		const parsed = new URL(trimmed, 'http://docxjs.invalid/');
		return SAFE_HREF_SCHEMES.has(parsed.protocol);
	} catch {
		// Non-URL strings that aren't fragments are almost always relative
		// paths like `foo/bar.html`. Treat as safe — no scheme, no sink.
		return !/^[a-z][a-z0-9+.-]*:/i.test(trimmed);
	}
}

// XPath expressions used by <w:dataBinding> in content controls are
// DOCX-attacker-controlled. Evaluating them with document.evaluate is safe
// when scoped to a CustomXmlPart's XML document (no scripts can run in a
// plain XML DOM parsed from a zipped part). This allowlist is a
// belt-and-braces defence: reject anything that mentions the rendered HTML
// `document` or `window` identifiers, shell-out-style extension function
// prefixes, or processing-instruction/comment lookups we don't need.
// Accepted expressions look like `/ns:root/ns:person/ns:name`,
// `/ns0:x[1]`, `//@attr`, etc. — the subset Word actually produces for
// custom-XML bindings.
//
// Exported for unit testing.
export function isSafeCustomXmlXPath(xp: string): boolean {
	if (typeof xp !== 'string') return false;
	if (xp.length === 0 || xp.length > 2000) return false;
	// Reject identifiers that have no business appearing in a document-
	// internal XPath. `document(…)`, `window`, `eval`, Function.call,
	// extension-function namespaces — none of these are used by Word.
	if (/\b(document|window|eval|Function|require|import)\b/i.test(xp)) return false;
	// Reject semicolons and braces — they aren't valid in XPath 1.0 and
	// their presence hints at embedded expressions in a different language.
	if (/[;{}]/.test(xp)) return false;
	// Accept characters that legitimately appear in XPath 1.0: letters,
	// digits, `_`, `-`, `.`, `:`, `/`, `[`, `]`, `(`, `)`, `=`, `*`, `|`,
	// `,`, `!`, `<`, `>`, `@`, whitespace, and the quote characters used
	// around string literals.
	return /^[\w\s\-./:[\]()=*|,!<>@"'$+]+$/.test(xp);
}

// Evaluate `xpath` against `xmlDoc` using `hostDoc.evaluate` if available,
// falling back to a manual walk for the simplest `/ns0:a/ns0:b` path
// expressions so the glossary/data-bound pipeline still works in jsdom
// when the host document has no XPath support. Returns the first matching
// node's text, empty string if the XPath evaluated but matched nothing,
// or null on any error.
//
// Exported for unit testing.
export function safeEvaluateXPath(hostDoc: any, xmlDoc: any, xpath: string): string | null {
	try {
		if (hostDoc?.evaluate) {
			// Build a namespace resolver that maps every prefix to the
			// document-element's namespaceURI. This covers the single-
			// namespace case (the vast majority of custom XML parts).
			const rootNs = xmlDoc?.documentElement?.namespaceURI ?? null;
			const resolver = rootNs ? (_: string) => rootNs : null;
			const FIRST_ORDERED_NODE_TYPE = 9;
			const res = hostDoc.evaluate(
				xpath,
				xmlDoc,
				resolver,
				FIRST_ORDERED_NODE_TYPE,
				null
			);
			const node = res?.singleNodeValue;
			if (node == null) return '';
			return node.textContent ?? '';
		}
	} catch {
		// Fall through to the manual walker.
	}
	// Minimal fallback: `/root/child/child[…]` with optional `nsX:` prefixes
	// on each step. Predicates are ignored (return the first match at each
	// step). Good enough for Word's typical bindings; anything richer
	// needs a real XPath engine and returns null here.
	try {
		const steps = xpath.split('/').filter(s => s.length > 0);
		let current: any = xmlDoc?.documentElement;
		if (!current) return null;
		// If the first step matches the root element's localName, advance
		// past it; otherwise we were given a relative path starting with
		// the root's first child.
		const first = steps[0]?.replace(/\[.*\]$/, '').split(':').pop();
		if (first && first === current.localName) {
			steps.shift();
		}
		for (const step of steps) {
			const localName = step.replace(/\[.*\]$/, '').split(':').pop();
			if (!localName) return null;
			let next: any = null;
			for (let i = 0; i < current.childNodes.length; i++) {
				const c = current.childNodes[i];
				if (c.nodeType === 1 && c.localName === localName) {
					next = c;
					break;
				}
			}
			if (!next) return '';
			current = next;
		}
		return current.textContent ?? '';
	} catch {
		return null;
	}
}

// Returns the fldCharType of the first WmlFieldChar nested inside the element,
// or null if this element doesn't represent a field-char delimiter run.
function complexFieldCharType(elem: OpenXmlElement): string | null {
	if (!elem || elem.type !== DomType.Run) return null;
	const run = elem as WmlRun;
	if (!run.fieldRun || !run.children) return null;
	for (const c of run.children) {
		if (c.type === DomType.ComplexField) return (c as WmlFieldChar).charType;
	}
	return null;
}

function isComplexFieldBeginRun(elem: OpenXmlElement): boolean {
	return complexFieldCharType(elem) === 'begin';
}

// HYPERLINK switches that take a quoted value argument in Word's
// instruction syntax. Anything not in this set is treated as a flag-only
// switch (\l, \h, \m, \n), which means the token that follows it is an
// independent positional argument, not its value.
const HYPERLINK_VALUE_SWITCHES = new Set(['\\o', '\\t']);

// Returns the value token that immediately follows `switchName` in the
// parsed instruction's ordered token list, or null if the switch has no
// value (or isn't present). Used by the HYPERLINK wrapper to pair \o with
// its tooltip string and \t with its target frame. Comparison is case-
// insensitive because Word writes both \o and \O in real documents.
function extractSwitchValue(
	parsed: { tokens?: string[] },
	switchName: string,
): string | null {
	const tokens = parsed.tokens ?? [];
	const target = switchName.toLowerCase();
	for (let i = 0; i < tokens.length; i++) {
		if (tokens[i].toLowerCase() === target) {
			const next = tokens[i + 1];
			if (next && !next.startsWith('\\')) return next;
			return null;
		}
	}
	return null;
}

// Returns the first positional argument (URL / anchor name) from a
// HYPERLINK instruction. Skips flag-only switches (\l, \h, \m, \n) and
// skips value-taking switches along with their value (\o "tip", \t "_blank").
function firstNonSwitchArg(parsed: { tokens?: string[] }): string | null {
	const tokens = parsed.tokens ?? [];
	let i = 0;
	while (i < tokens.length) {
		const t = tokens[i];
		if (t.startsWith('\\')) {
			if (HYPERLINK_VALUE_SWITCHES.has(t.toLowerCase())) {
				const next = tokens[i + 1];
				if (next && !next.startsWith('\\')) {
					i += 2;
					continue;
				}
			}
			i += 1;
			continue;
		}
		return t;
	}
	return null;
}

// Concatenates the text of every w:instrText inside the instruction-portion
// runs of a complex field. Word sometimes serialises one instruction across
// several runs, and a single run's children may mix <w:instrText> with other
// content (e.g. a stray <w:t>). Only the <w:instrText> children contribute
// to the instruction string — the run itself is a fieldRun, so any non-
// instruction children would have rendered to nothing anyway thanks to the
// fieldRun guard in renderRun(). This split is deliberate: we need the
// instruction text here, but we must never let the rendered output of a
// field-delimiter / instruction-portion run leak into the DOM.
function collectInstructionText(runs: OpenXmlElement[]): string {
	let out = '';
	for (const r of runs) {
		if (!r || r.type !== DomType.Run || !r.children) continue;
		for (const c of r.children) {
			if (c.type === DomType.Instruction) {
				out += (c as WmlInstructionText).text ?? '';
			}
			// Non-instrText children in instruction-portion runs are dropped
			// on purpose; the fieldRun guard in renderRun already suppresses
			// their visible output.
		}
	}
	return out;
}

// OMML → MathML tag routing for n-ary operators. `limLoc` values (parsed from
// m:limLoc/@val) are attacker-controlled; they must go through this allowlist
// before being used as a MathML tag name. Unknown values fall back to
// Word's rendered default, which depends on the operator character.
function resolveNaryLimitTag(limLoc: string | undefined, opChar: string): "munderover" | "msubsup" {
	if (limLoc === "subSup") return "msubsup";
	if (limLoc === "undOvr") return "munderover";
	// Default follows Word: big operators (∑ U+2211, ∏ U+220F, ⋃ U+22C3,
	// ⋂ U+22C2, ⨁ U+2A01, ⨂ U+2A02, ⨀ U+2A00) take under/over limits;
	// integrals (∫) and everything else take sub/sup.
	const BIG_OP = new Set(['∑', '∏', '⋃', '⋂', '⨁', '⨂', '⨀']);
	return BIG_OP.has(opChar) ? "munderover" : "msubsup";
}

// OMML → MathML tag routing for sGroup. pos/vertJc are attacker-controlled;
// the switch below is an explicit allowlist. Unknown values fall back to
// munderover (the most permissive 3-slot wrapper) which renders reasonably
// even with empty scripts.
function resolveGroupTag(pos: string | undefined, vertJc: string | undefined): "munder" | "mover" | "munderover" {
	const hasTop = pos === "top" || vertJc === "top";
	const hasBot = pos === "bot" || pos === "bottom" || vertJc === "bot" || vertJc === "bottom";
	if (hasTop && hasBot) return "munderover";
	if (hasTop) return "mover";
	if (hasBot) return "munder";
	return "munderover";
}

// Internal-only — addresses a rendered change element via data-change-kind.
// Not exported; the library is read-only so consumers never see this.
type ChangeKind =
	| 'insertion'
	| 'deletion'
	| 'formatting'
	| 'move'
	| 'paragraphMark'
	| 'rowInsertion'
	| 'rowDeletion';

interface CellPos {
	col: number;
	row: number;
}

